{-# LANGUAGE OverloadedStrings #-}

module Main where

import Control.Monad (void)

import qualified Graphics.UI.Threepenny as UI
import Graphics.UI.Threepenny.Core

uiVersion :: String
uiVersion = "Threepenny UI v1.0.6 - absolute angle arcs - 2026-05-30"

main :: IO ()
main = do
  putStrLn "Starting Haskell Four-Bar Linkage Simulator with Threepenny-GUI..."
  putStrLn "Open http://127.0.0.1:8023 if the browser does not open automatically."
  startGUI defaultConfig
    { jsPort   = Just 8023
    , jsStatic = Just "."
    } setup

setup :: Window -> UI ()
setup window = void $ do
  return window # set title ("Haskell Four-Bar Linkage Simulator - " ++ uiVersion)

  styleEl <- UI.mkElement "style" # set UI.text appCss
  getHead window #+ [element styleEl]

  body <- getBody window
  element body # set (attr "class") "app-body"

  root <- UI.div # set (attr "id") "app-root"
  element body #+ [element root]
  element root # set UI.html appHtml

  runFunction $ ffi appJs
  return ()

appHtml :: String
appHtml = "<div class=\"app-shell\">\n  <aside class=\"side-panel\">\n    <h1>Four-Bar Linkage</h1>\n    <p>Lengths in cm · Threepenny/SVG GUI · Local Inter font · Smooth browser-side animation</p>\n\n    <div class=\"slider-card\">\n      <div class=\"slider-label\"><span>Ground link g</span><span class=\"slider-value\" id=\"val-g\">24.0 cm</span></div>\n      <input id=\"slider-g\" type=\"range\" min=\"5\" max=\"40\" step=\"0.1\" value=\"24\" aria-label=\"Ground link g\">\n    </div>\n\n    <div class=\"slider-card\">\n      <div class=\"slider-label\"><span>Input link a</span><span class=\"slider-value\" id=\"val-a\">10.0 cm</span></div>\n      <input id=\"slider-a\" type=\"range\" min=\"5\" max=\"40\" step=\"0.1\" value=\"10\" aria-label=\"Input link a\">\n    </div>\n\n    <div class=\"slider-card\">\n      <div class=\"slider-label\"><span>Output link b</span><span class=\"slider-value\" id=\"val-b\">18.0 cm</span></div>\n      <input id=\"slider-b\" type=\"range\" min=\"5\" max=\"40\" step=\"0.1\" value=\"18\" aria-label=\"Output link b\">\n    </div>\n\n    <div class=\"slider-card\">\n      <div class=\"slider-label\"><span>Floating link f</span><span class=\"slider-value\" id=\"val-f\">20.0 cm</span></div>\n      <input id=\"slider-f\" type=\"range\" min=\"5\" max=\"40\" step=\"0.1\" value=\"20\" aria-label=\"Floating link f\">\n    </div>\n\n    <div class=\"slider-card speed-card\">\n      <div class=\"slider-label\"><span>Animation speed</span><span class=\"slider-value\" id=\"val-speed\">60 steps/s</span></div>\n      <input id=\"slider-speed\" type=\"range\" min=\"5\" max=\"120\" step=\"1\" value=\"60\" aria-label=\"Animation speed\">\n    </div>\n\n    <div class=\"state-box\" id=\"state-box\"></div>\n    <div class=\"shortcut-box\"><strong>Controls:</strong> Space = Play/Pause · F = flip branch · R = reset</div>\n  </aside>\n\n  <main class=\"main-panel\">\n    <div class=\"main-header\">\n      <div class=\"main-title\">Main mechanism pane</div>\n      <div class=\"version-badge\">Threepenny UI v1.0.6 · absolute angle arcs</div>\n    </div>\n    <div class=\"top-readout\" id=\"top-readout\"></div>\n    <div class=\"mechanism-stage\" id=\"svg-host\"></div>\n    <div class=\"action-row\">\n      <button id=\"playPauseBtn\" class=\"primary-action play\">Play</button>\n      <button id=\"flipBranchBtn\" class=\"secondary-action\">Flip branch</button>\n      <button id=\"resetBtn\" class=\"secondary-action\">Reset</button>\n    </div>\n    <div class=\"bottom-alert info\" id=\"bottom-alert\"></div>\n  </main>\n</div>\n<div class=\"size-warning\">The viewport is below the requested 650 px minimum width; horizontal clipping may occur.</div>"

appCss :: String
appCss = "@font-face {\n  font-family: 'InterLocal';\n  src: url('/static/resources/fonts/Inter-Regular.ttf') format('truetype');\n  font-weight: 400;\n  font-style: normal;\n  font-display: swap;\n}\n* { box-sizing: border-box; }\nhtml, body { width: 100%; height: 100%; margin: 0; padding: 0; }\nbody.app-body {\n  min-width: 650px;\n  width: 100vw;\n  height: 100vh;\n  overflow: hidden;\n  background: #ffffff;\n  color: #0f172a;\n  font-family: 'InterLocal', Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;\n}\n#app-root { width: 100vw; height: 100vh; }\n.app-shell {\n  width: 100vw;\n  height: 100vh;\n  min-width: 650px;\n  display: grid;\n  grid-template-columns: minmax(320px, 26vw) minmax(0, 1fr);\n  overflow: hidden;\n  background: #ffffff;\n}\n.side-panel {\n  background: linear-gradient(180deg, #111827, #1e293b);\n  color: #f8fafc;\n  padding: clamp(12px, 1.35vw, 22px);\n  display: flex;\n  flex-direction: column;\n  gap: clamp(8px, 0.82vw, 14px);\n  min-width: 0;\n  min-height: 0;\n  overflow-y: auto;\n  overflow-x: hidden;\n  scrollbar-width: thin;\n}\n.side-panel h1 { font-size: clamp(22px, 1.8vw, 34px); line-height: 1.05; margin: 0; letter-spacing: -0.04em; }\n.side-panel p { margin: 0; color: #cbd5e1; font-size: clamp(11px, 0.82vw, 14px); line-height: 1.45; }\n.slider-card { background: rgba(255,255,255,0.06); border: 1px solid rgba(226,232,240,0.12); border-radius: 16px; padding: clamp(10px, 0.9vw, 15px); flex: 0 0 auto; }\n.slider-label { display: flex; justify-content: space-between; align-items: center; gap: 10px; margin-bottom: 8px; color: #e2e8f0; font-size: clamp(11px, 0.88vw, 15px); font-weight: 800; }\n.slider-value { white-space: nowrap; color: #93c5fd; font-variant-numeric: tabular-nums; font-weight: 900; }\n.slider-card.speed-card { border-color: rgba(96,165,250,0.38); background: rgba(59,130,246,0.12); }\ninput[type='range'] { width: 100%; accent-color: #60a5fa; cursor: pointer; touch-action: none; }\n.state-box { margin-top: clamp(4px, 0.75vw, 10px); background: rgba(15,23,42,0.66); border: 1px solid rgba(148,163,184,0.22); border-radius: 18px; padding: clamp(10px, 0.95vw, 16px); flex: 0 0 auto; }\n.state-box h2 { margin: 0 0 8px 0; font-size: clamp(13px, 1vw, 17px); }\n.state-row { display: flex; justify-content: space-between; gap: 10px; color: #cbd5e1; border-top: 1px solid rgba(148,163,184,0.15); padding: 5px 0; font-size: clamp(10px, 0.77vw, 13px); }\n.state-row strong { color: #f8fafc; text-align: right; font-variant-numeric: tabular-nums; }\n.shortcut-box { color: #cbd5e1; font-size: clamp(9px, 0.72vw, 12px); line-height: 1.45; padding-bottom: 8px; flex: 0 0 auto; }\n.main-panel { min-width: 0; min-height: 0; height: 100vh; background: #f8fafc; padding: clamp(8px, 0.75vw, 14px); display: grid; grid-template-rows: auto auto minmax(0, 1fr) auto auto; gap: clamp(7px, 0.68vw, 11px); overflow: hidden; }\n.main-header { display: flex; justify-content: space-between; align-items: start; gap: 12px; }\n.main-title { font-size: clamp(19px, 1.55vw, 28px); font-weight: 900; letter-spacing: -0.035em; }\n.version-badge { color: #64748b; background: #e2e8f0; padding: 5px 10px; border-radius: 999px; font-size: clamp(8px, 0.68vw, 12px); white-space: nowrap; }\n.top-readout { background: #ffffff; border: 1px solid #e2e8f0; border-radius: 16px; padding: clamp(8px, 0.72vw, 12px) clamp(10px, 0.95vw, 16px); box-shadow: 0 10px 30px rgba(15,23,42,0.06); }\n.angle-line { font-size: clamp(16px, 1.35vw, 24px); font-weight: 950; color: #1e293b; }\n.state-line { color: #64748b; font-size: clamp(10px, 0.86vw, 15px); margin-top: 3px; }\n.motion-line { color: #475569; font-size: clamp(10px, 0.8vw, 13px); margin-top: 3px; font-weight: 800; }\n.mechanism-stage { min-height: 0; height: 100%; display: grid; place-items: center; background: #ffffff; border: 1px solid #e2e8f0; border-radius: 20px; overflow: hidden; }\n.mechanism-svg { width: 100%; height: 100%; display: block; font-family: 'InterLocal', Inter, system-ui, sans-serif; shape-rendering: geometricPrecision; }\n.action-row { display: flex; justify-content: end; gap: 10px; flex-wrap: wrap; }\nbutton { font-family: inherit; border: none; border-radius: 14px; padding: clamp(9px, 0.75vw, 13px) clamp(14px, 1.08vw, 22px); font-weight: 950; cursor: pointer; box-shadow: 0 12px 24px rgba(15,23,42,0.12); }\n.primary-action.play { background: #16a34a; color: white; }\n.primary-action.pause { background: #f59e0b; color: #111827; }\n.secondary-action { background: #e2e8f0; color: #0f172a; }\n.bottom-alert { border-radius: 16px; padding: clamp(9px, 0.72vw, 12px) clamp(10px, 0.95vw, 16px); text-align: center; font-size: clamp(10px, 0.84vw, 14px); font-weight: 900; border: 2px solid; }\n.bottom-alert.info { background: #dbeafe; border-color: #2563eb; color: #172554; }\n.bottom-alert.warn { background: #fff7ed; border-color: #ea580c; color: #431407; }\n.bottom-alert.danger { background: #fee2e2; border-color: #b91c1c; color: #450a0a; }\n.size-warning { display: none; position: fixed; left: 12px; right: 12px; bottom: 12px; z-index: 50; background: #7f1d1d; color: white; padding: 10px 12px; border-radius: 12px; text-align: center; font-size: 12px; }\n@media (max-width: 760px) { .app-shell { grid-template-columns: minmax(280px, 40vw) minmax(0, 1fr); } .version-badge { display: none; } }\n@media (max-width: 649px) { .size-warning { display: block; } }"

appJs :: String
appJs = "(function () {\n  if (window.__fourbarClientSideAppInstalled) return;\n  window.__fourbarClientSideAppInstalled = true;\n\n  const TAU = Math.PI * 2;\n  const DEG = Math.PI / 180;\n  const sliderMin = 5;\n  const sliderMax = 40;\n  const speedMin = 5;\n  const speedMax = 120;\n\n  const initial = {\n    g: 24,\n    a: 10,\n    b: 18,\n    f: 20,\n    alpha: Math.PI / 4,\n    direction: 1,\n    playing: false,\n    branch: 1,\n    speed: 60,\n    betaSign: 1\n  };\n\n  const state = Object.assign({}, initial);\n  let lastFrameTime = 0;\n  let accumulator = 0;\n  let dirty = true;\n\n  const $ = (id) => document.getElementById(id);\n\n  function clamp(lo, hi, x) { return Math.max(lo, Math.min(hi, x)); }\n  function positiveModulo(x, m) { return x - Math.floor(x / m) * m; }\n  function normalizeAngle(x) {\n    const y = positiveModulo(x, TAU);\n    return y < 0 ? y + TAU : y;\n  }\n  function toDegrees(x) { return 180 * x / Math.PI; }\n  function fmt1(x) { return Number(x).toFixed(1); }\n  function fmt2(x) { return Number(x).toFixed(2); }\n  function esc(s) {\n    return String(s)\n      .replaceAll('&', '&amp;')\n      .replaceAll('<', '&lt;')\n      .replaceAll('>', '&gt;')\n      .replaceAll('\"', '&quot;')\n      .replaceAll(\"'\", '&#39;');\n  }\n\n  function sortedLengths(st) { return [st.g, st.a, st.b, st.f].sort((x, y) => x - y); }\n  function grashofIndex(st) {\n    const [s, p, q, l] = sortedLengths(st);\n    return s + l - p - q;\n  }\n  function validityIndex(st) {\n    const [s, p, q, l] = sortedLengths(st);\n    return l - s - p - q;\n  }\n  function isAssemblable(st) { return validityIndex(st) <= 1.0e-7; }\n  function isGrashof(st) { return isAssemblable(st) && grashofIndex(st) <= 1.0e-7; }\n  function excesses(st) {\n    return [st.g + st.f - st.b - st.a, st.b + st.g - st.f - st.a, st.f + st.b - st.g - st.a];\n  }\n  function signCode(x) {\n    if (Math.abs(x) <= 1.0e-6) return '0';\n    return x > 0 ? '+' : '-';\n  }\n  function signTriple(st) { return excesses(st).map(signCode).join(''); }\n  function classifyMotion(st) {\n    const table = {\n      '+++': ['crank', 'rocker'], '++0': ['crank', 'π-rocker'], '++-': ['0-rocker', 'π-rocker'],\n      '0++': ['crank', 'π-rocker'], '0+0': ['crank', 'π-rocker'], '0+-': ['0-rocker', 'π-rocker'],\n      '-++': ['π-rocker', 'π-rocker'], '-+0': ['π-rocker', 'π-rocker'], '-+-': ['rocker', 'rocker'],\n      '+0+': ['crank', '0-rocker'], '+00': ['crank', 'crank'], '+0-': ['0-rocker', 'crank'],\n      '00+': ['crank', 'crank'], '000': ['crank', 'crank'], '00-': ['0-rocker', 'crank'],\n      '-0+': ['crank', 'crank'], '-00': ['crank', 'crank'], '-0-': ['0-rocker', '0-rocker'],\n      '+-+': ['π-rocker', '0-rocker'], '+-0': ['π-rocker', 'crank'], '+--': ['rocker', 'crank'],\n      '0-+': ['crank', 'crank'], '0-0': ['crank', 'crank'], '0--': ['0-rocker', 'crank'],\n      '--+': ['crank', 'crank'], '--0': ['crank', 'crank'], '---': ['0-rocker', '0-rocker']\n    };\n    return table[signTriple(st)] || ['unknown', 'unknown'];\n  }\n  function plainMotion(s) {\n    if (s.includes('crank')) return 'crank';\n    if (s.includes('rocker')) return 'rocker';\n    return 'unknown';\n  }\n  function basicMotionState(st) {\n    const [i, o] = classifyMotion(st);\n    return plainMotion(i) + ' - ' + plainMotion(o);\n  }\n\n  function solvePose(st, rawAlpha) {\n    if (!isAssemblable(st)) return null;\n    const alpha = normalizeAngle(rawAlpha);\n    const cx = st.a * Math.cos(alpha);\n    const cy = st.a * Math.sin(alpha);\n    const dx = st.g - cx;\n    const dy = -cy;\n    const d = Math.sqrt(dx * dx + dy * dy);\n    const eps = 1.0e-7;\n    if (d <= eps) return null;\n    if (d > st.f + st.b + eps) return null;\n    if (d < Math.abs(st.f - st.b) - eps) return null;\n\n    const aDist = (st.f * st.f - st.b * st.b + d * d) / (2 * d);\n    const h2 = st.f * st.f - aDist * aDist;\n    const h = Math.sqrt(Math.max(0, h2));\n    const ux = dx / d;\n    const uy = dy / d;\n    const px = cx + aDist * ux;\n    const py = cy + aDist * uy;\n    const orient = st.branch >= 0 ? 1 : -1;\n    const ddx = px + orient * h * (-uy);\n    const ddy = py + orient * h * ux;\n    const beta = normalizeAngle(Math.atan2(ddy, ddx - st.g));\n\n    return {\n      A: [0, 0],\n      B: [st.g, 0],\n      C: [cx, cy],\n      D: [ddx, ddy],\n      alphaRad: alpha,\n      betaRad: beta\n    };\n  }\n\n  function angularDistance(a, b) {\n    const d = Math.abs(normalizeAngle(a - b));\n    return Math.min(d, TAU - d);\n  }\n  function nearestValidAlpha(st, current) {\n    let best = null;\n    let bestD = Infinity;\n    for (let k = 0; k < 720; k++) {\n      const a = TAU * k / 720;\n      if (solvePose(st, a)) {\n        const d = angularDistance(current, a);\n        if (d < bestD) { best = a; bestD = d; }\n      }\n    }\n    return best;\n  }\n  function signedAngleDiff(a, b) {\n    let d = normalizeAngle(a - b);\n    if (d > Math.PI) d -= TAU;\n    return d;\n  }\n  function betaDirection(st, pose) {\n    const probe = Object.assign({}, st, { alpha: normalizeAngle(st.alpha + st.direction * DEG) });\n    const next = solvePose(probe, probe.alpha);\n    if (!next) return state.betaSign || 1;\n    const d = signedAngleDiff(next.betaRad, pose.betaRad);\n    if (Math.abs(d) < 1.0e-7) return state.betaSign || 1;\n    return d > 0 ? 1 : -1;\n  }\n\n  function updateSliderLabels() {\n    $('val-g').textContent = fmt1(state.g) + ' cm';\n    $('val-a').textContent = fmt1(state.a) + ' cm';\n    $('val-b').textContent = fmt1(state.b) + ' cm';\n    $('val-f').textContent = fmt1(state.f) + ' cm';\n    $('val-speed').textContent = Math.round(state.speed) + ' steps/s';\n  }\n\n  function syncSliderInputs() {\n    $('slider-g').value = state.g;\n    $('slider-a').value = state.a;\n    $('slider-b').value = state.b;\n    $('slider-f').value = state.f;\n    $('slider-speed').value = state.speed;\n    updateSliderLabels();\n  }\n\n  function setLength(key, value) {\n    state[key] = clamp(sliderMin, sliderMax, Number(value));\n    const pose = solvePose(state, state.alpha);\n    if (!pose) {\n      const nearest = nearestValidAlpha(state, state.alpha);\n      if (nearest !== null) state.alpha = nearest;\n    }\n    dirty = true;\n    render();\n  }\n\n  function setSpeed(value) {\n    state.speed = clamp(speedMin, speedMax, Number(value));\n    dirty = true;\n    render();\n  }\n\n  function stepAnimation() {\n    if (!state.playing || !isAssemblable(state)) return;\n    const candidate = normalizeAngle(state.alpha + state.direction * DEG);\n    if (solvePose(state, candidate)) {\n      state.alpha = candidate;\n      return;\n    }\n    state.direction = -state.direction;\n    const bounce = normalizeAngle(state.alpha + state.direction * DEG);\n    if (solvePose(state, bounce)) state.alpha = bounce;\n  }\n\n  function installEvents() {\n    $('slider-g').addEventListener('input', e => setLength('g', e.target.value));\n    $('slider-a').addEventListener('input', e => setLength('a', e.target.value));\n    $('slider-b').addEventListener('input', e => setLength('b', e.target.value));\n    $('slider-f').addEventListener('input', e => setLength('f', e.target.value));\n    $('slider-speed').addEventListener('input', e => setSpeed(e.target.value));\n\n    $('playPauseBtn').addEventListener('click', () => {\n      state.playing = !state.playing;\n      lastFrameTime = 0;\n      accumulator = 0;\n      dirty = true;\n      render();\n    });\n    $('flipBranchBtn').addEventListener('click', () => {\n      state.branch *= -1;\n      const pose = solvePose(state, state.alpha);\n      if (!pose) {\n        const nearest = nearestValidAlpha(state, state.alpha);\n        if (nearest !== null) state.alpha = nearest;\n      }\n      dirty = true;\n      render();\n    });\n    $('resetBtn').addEventListener('click', () => {\n      Object.assign(state, initial);\n      syncSliderInputs();\n      lastFrameTime = 0;\n      accumulator = 0;\n      dirty = true;\n      render();\n    });\n\n    document.addEventListener('keydown', (e) => {\n      const tag = (document.activeElement && document.activeElement.tagName || '').toUpperCase();\n      if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;\n      if (e.code === 'Space') { e.preventDefault(); $('playPauseBtn').click(); }\n      if (e.key === 'f' || e.key === 'F') { $('flipBranchBtn').click(); }\n      if (e.key === 'r' || e.key === 'R') { $('resetBtn').click(); }\n    });\n  }\n\n  function animationFrame(now) {\n    if (!lastFrameTime) lastFrameTime = now;\n    const dt = now - lastFrameTime;\n    lastFrameTime = now;\n\n    if (state.playing) {\n      accumulator += dt;\n      const interval = 1000 / clamp(speedMin, speedMax, state.speed);\n      // Render at most one exact 1-degree step per animation frame. This avoids\n      // multi-step visual jumps when the browser temporarily misses a frame.\n      if (accumulator >= interval) {\n        accumulator = accumulator - Math.floor(accumulator / interval) * interval;\n        stepAnimation();\n        dirty = true;\n      }\n    } else {\n      accumulator = 0;\n    }\n\n    if (dirty) {\n      render();\n      dirty = false;\n    }\n    window.requestAnimationFrame(animationFrame);\n  }\n\n  function renderReadout(pose) {\n    const [inputType, outputType] = classifyMotion(state);\n    const branchText = state.branch >= 0 ? 'upper branch' : 'lower branch';\n    const alphaText = pose ? 'α = ' + fmt1(toDegrees(pose.alphaRad)) + '°' : 'α = --';\n    const betaText = pose ? 'β = ' + fmt1(toDegrees(pose.betaRad)) + '°' : 'β = --';\n    const alphaMotion = state.direction >= 0 ? 'α increasing ↺' : 'α decreasing ↻';\n    const betaMotion = state.betaSign >= 0 ? 'β increasing ↺' : 'β decreasing ↻';\n    $('top-readout').innerHTML =\n      '<div class=\"angle-line\">' + alphaText + ' &nbsp;&nbsp; ' + betaText + '</div>' +\n      '<div class=\"state-line\">Input: <strong>' + esc(inputType) + '</strong> · Output: <strong>' + esc(outputType) + '</strong> · Basic state: <strong>' + esc(basicMotionState(state)) + '</strong> · ' + branchText + ' · Speed: <strong>' + Math.round(state.speed) + ' steps/s</strong> · <strong>1°/step</strong></div>' +\n      '<div class=\"motion-line\">Arc arrows: ' + alphaMotion + ' · ' + betaMotion + '</div>';\n  }\n\n  function renderStateBox() {\n    const gIdx = grashofIndex(state);\n    const vIdx = validityIndex(state);\n    const [t1, t2, t3] = excesses(state);\n    const [iLabel, oLabel] = classifyMotion(state);\n    const validText = isAssemblable(state) ? 'valid assembly' : 'invalid assembly';\n    const grText = isGrashof(state) ? 'Grashof' : 'non-Grashof';\n    const branchText = state.branch >= 0 ? 'upper' : 'lower';\n    const row = (a, b) => '<div class=\"state-row\"><span>' + esc(a) + '</span><strong>' + esc(b) + '</strong></div>';\n    $('state-box').innerHTML =\n      '<h2>Indices and state</h2>' +\n      row('G', fmt2(gIdx) + ' cm') +\n      row('V', fmt2(vIdx) + ' cm') +\n      row('T1 / T2 / T3', fmt1(t1) + ' / ' + fmt1(t2) + ' / ' + fmt1(t3)) +\n      row('Input', iLabel) +\n      row('Output', oLabel) +\n      row('Class', grText + ' / ' + validText) +\n      row('Branch', branchText) +\n      row('Step', '1.0°') +\n      row('Speed', Math.round(state.speed) + ' steps/s');\n  }\n\n  function renderAlert() {\n    const [inputType, outputType] = classifyMotion(state);\n    const gIdx = grashofIndex(state);\n    const vIdx = validityIndex(state);\n    const gr = isGrashof(state) ? 'Grashof mechanism' : 'Non-Grashof mechanism';\n    const validity = isAssemblable(state) ? 'valid' : 'invalid: longest link is too long';\n    const cls = !isAssemblable(state) ? 'danger' : (isGrashof(state) ? 'info' : 'warn');\n    const el = $('bottom-alert');\n    el.className = 'bottom-alert ' + cls;\n    el.textContent = gr + ' | ' + validity + ' | state: ' + inputType + ' -> ' + outputType + ' | G=' + fmt2(gIdx) + ' cm, V=' + fmt2(vIdx) + ' cm';\n  }\n\n  function renderButtons() {\n    const btn = $('playPauseBtn');\n    btn.textContent = state.playing ? 'Pause' : 'Play';\n    btn.className = 'primary-action ' + (state.playing ? 'pause' : 'play');\n  }\n\n  function render() {\n    const pose = solvePose(state, state.alpha);\n    if (pose) state.betaSign = betaDirection(state, pose);\n    syncSliderInputs();\n    renderReadout(pose);\n    renderStateBox();\n    renderAlert();\n    renderButtons();\n    $('svg-host').innerHTML = pose ? assembledSvg(pose) : unassembledSvg();\n  }\n\n  function mechanismScale() {\n    const total = state.g + state.a + state.b + state.f;\n    const maxLen = Math.max(state.g, state.a, state.b, state.f);\n    const sx = 920 / Math.max(1, total);\n    const sy = 540 / Math.max(1, 2.0 * maxLen);\n    return Math.max(7.0, Math.min(26.0, Math.min(sx, sy)));\n  }\n  function toSvg(p, sc) {\n    return [500 + sc * (p[0] - state.g / 2), 330 - sc * p[1]];\n  }\n  function line(color, width, p1, p2, extra) {\n    extra = extra || '';\n    return '<line x1=\"' + p1[0].toFixed(3) + '\" y1=\"' + p1[1].toFixed(3) + '\" x2=\"' + p2[0].toFixed(3) + '\" y2=\"' + p2[1].toFixed(3) + '\" stroke=\"' + color + '\" stroke-width=\"' + width + '\" stroke-linecap=\"round\" ' + extra + '/>';\n  }\n  function rod(color, width, p1, p2) {\n    return line(color, width, p1, p2) + line('rgba(255,255,255,0.38)', 4, p1, p2);\n  }\n  function text(p, color, size, s, weight) {\n    return '<text x=\"' + p[0].toFixed(3) + '\" y=\"' + p[1].toFixed(3) + '\" fill=\"' + color + '\" font-size=\"' + size + '\" font-weight=\"' + (weight || 800) + '\">' + esc(s) + '</text>';\n  }\n  function centeredText(x, y, color, size, s) {\n    return '<text x=\"' + x.toFixed(3) + '\" y=\"' + y.toFixed(3) + '\" fill=\"' + color + '\" font-size=\"' + size + '\" font-weight=\"800\" text-anchor=\"middle\">' + esc(s) + '</text>';\n  }\n  function pivot(name, p) {\n    const [x, y] = p;\n    return '<circle cx=\"' + x.toFixed(3) + '\" cy=\"' + y.toFixed(3) + '\" r=\"17\" fill=\"#ffffff\" stroke=\"#0f172a\" stroke-width=\"3\"/>' +\n      '<circle cx=\"' + x.toFixed(3) + '\" cy=\"' + y.toFixed(3) + '\" r=\"4.5\" fill=\"#0f172a\"/>' +\n      text([x + 24, y - 22], '#0f172a', 20, name, 850);\n  }\n  function groundPivot(name, p) {\n    const [x, y] = p;\n    let s = '<polygon points=\"' + (x - 34).toFixed(2) + ',' + (y + 52).toFixed(2) + ' ' + (x + 34).toFixed(2) + ',' + (y + 52).toFixed(2) + ' ' + x.toFixed(2) + ',' + (y + 18).toFixed(2) + '\" fill=\"#e2e8f0\" stroke=\"#334155\" stroke-width=\"2\"/>';\n    s += line('#334155', 2, [x - 42, y + 52], [x + 42, y + 52]);\n    [-36, -16, 4, 24].forEach(dx => { s += line('#334155', 2, [x + dx, y + 64], [x + dx + 12, y + 52]); });\n    return s + pivot(name, p);\n  }\n  function linkLabel(label, color, p1, p2, off) {\n    const mx = (p1[0] + p2[0]) / 2 + off[0];\n    const my = (p1[1] + p2[1]) / 2 + off[1];\n    return '<rect x=\"' + (mx - 23).toFixed(3) + '\" y=\"' + (my - 24).toFixed(3) + '\" width=\"46\" height=\"34\" rx=\"10\" fill=\"rgba(255,255,255,0.92)\" stroke=\"#e2e8f0\"/>' + centeredText(mx, my - 1, color, 22, label);\n  }\n  function grid() {\n    let s = '';\n    for (let y = 80; y <= 500; y += 55) s += line('#eef2f7', 1, [70, y], [930, y]);\n    for (let x = 80; x <= 920; x += 60) s += line('#eef2f7', 1, [x, 80], [x, 500]);\n    return s;\n  }\n  function anglePoint(center, r, theta) {\n    return [center[0] + r * Math.cos(theta), center[1] - r * Math.sin(theta)];\n  }\n  function arcArrow(center, r, theta, sign, color, markerId, label) {\n    const eps = 1.0e-5;\n    let angle = normalizeAngle(theta);\n    if (angle < eps || TAU - angle < eps) angle = 0;\n\n    const zero = anglePoint(center, r, 0);\n    let s = line(color, 1.5, center, zero, 'opacity=\"0.24\" stroke-dasharray=\"5 5\"');\n\n    if (angle > eps) {\n      const start = zero;\n      const end = anglePoint(center, r, angle);\n      const largeArc = angle > Math.PI ? 1 : 0;\n      const d = 'M ' + start[0].toFixed(3) + ' ' + start[1].toFixed(3) + ' A ' + r + ' ' + r + ' 0 ' + largeArc + ' 0 ' + end[0].toFixed(3) + ' ' + end[1].toFixed(3);\n      s += '<path d=\"' + d + '\" fill=\"none\" stroke=\"' + color + '\" stroke-width=\"3\" stroke-linecap=\"round\" opacity=\"0.86\"/>';\n    }\n\n    const arrowTheta = angle;\n    const tip = anglePoint(center, r, arrowTheta);\n    let tx = -Math.sin(arrowTheta);\n    let ty = -Math.cos(arrowTheta);\n    if (sign < 0) { tx = -tx; ty = -ty; }\n    const mag = Math.sqrt(tx * tx + ty * ty) || 1;\n    tx /= mag; ty /= mag;\n    const len = 15;\n    const half = 6;\n    const bx = tip[0] - tx * len;\n    const by = tip[1] - ty * len;\n    const nx = -ty;\n    const ny = tx;\n    const p1 = tip[0].toFixed(3) + ',' + tip[1].toFixed(3);\n    const p2 = (bx + nx * half).toFixed(3) + ',' + (by + ny * half).toFixed(3);\n    const p3 = (bx - nx * half).toFixed(3) + ',' + (by - ny * half).toFixed(3);\n    s += '<polygon points=\"' + p1 + ' ' + p2 + ' ' + p3 + '\" fill=\"' + color + '\" opacity=\"0.96\"/>';\n\n    const labelAngle = angle > eps ? angle * 0.5 : 0.24;\n    const labelPt = anglePoint(center, r + 34, labelAngle);\n    return s + centeredText(labelPt[0], labelPt[1], color, 15, label);\n  }\n  function defs() {\n    return '<defs>' +\n      '<marker id=\"arrowAlpha\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto-start-reverse\"><path d=\"M 0 0 L 10 5 L 0 10 z\" fill=\"#dc2626\"/></marker>' +\n      '<marker id=\"arrowBeta\" viewBox=\"0 0 10 10\" refX=\"8\" refY=\"5\" markerWidth=\"5\" markerHeight=\"5\" orient=\"auto-start-reverse\"><path d=\"M 0 0 L 10 5 L 0 10 z\" fill=\"#2563eb\"/></marker>' +\n      '</defs>';\n  }\n  function svgFrame(body) {\n    return '<svg class=\"mechanism-svg\" viewBox=\"0 0 1000 600\" preserveAspectRatio=\"xMidYMid meet\" xmlns=\"http://www.w3.org/2000/svg\">' +\n      defs() +\n      '<rect x=\"0\" y=\"0\" width=\"1000\" height=\"600\" rx=\"24\" fill=\"#ffffff\"/>' +\n      body +\n      '<text x=\"40\" y=\"566\" fill=\"#64748b\" font-size=\"17\">' + esc('g=' + fmt1(state.g) + ', a=' + fmt1(state.a) + ', b=' + fmt1(state.b) + ', f=' + fmt1(state.f) + ' cm') + '</text>' +\n      '</svg>';\n  }\n  function assembledSvg(pose) {\n    const sc = mechanismScale();\n    const A = toSvg(pose.A, sc);\n    const B = toSvg(pose.B, sc);\n    const C = toSvg(pose.C, sc);\n    const D = toSvg(pose.D, sc);\n    const alphaSign = state.direction >= 0 ? 1 : -1;\n    const betaSign = state.betaSign >= 0 ? 1 : -1;\n    const alphaLabel = alphaSign >= 0 ? 'α absolute ↑' : 'α absolute ↓';\n    const betaLabel = betaSign >= 0 ? 'β absolute ↑' : 'β absolute ↓';\n\n    let s = grid();\n    s += rod('#1f2937', 18, A, B);\n    s += rod('#dc2626', 16, A, C);\n    s += rod('#2563eb', 16, B, D);\n    s += rod('#16a34a', 16, C, D);\n    s += arcArrow(A, 64, pose.alphaRad, alphaSign, '#dc2626', 'arrowAlpha', alphaLabel);\n    s += arcArrow(B, 64, pose.betaRad, betaSign, '#2563eb', 'arrowBeta', betaLabel);\n    s += linkLabel('g', '#1f2937', A, B, [0, 42]);\n    s += linkLabel('a', '#dc2626', A, C, [0, -30]);\n    s += linkLabel('b', '#2563eb', B, D, [0, -30]);\n    s += linkLabel('f', '#16a34a', C, D, [0, -30]);\n    s += groundPivot('A', A);\n    s += groundPivot('B', B);\n    s += pivot('C', C);\n    s += pivot('D', D);\n    s += text([A[0] + 50, A[1] - 52], '#dc2626', 22, 'α = ' + fmt1(toDegrees(pose.alphaRad)) + '°', 900);\n    s += text([B[0] + 50, B[1] - 52], '#2563eb', 22, 'β = ' + fmt1(toDegrees(pose.betaRad)) + '°', 900);\n    return svgFrame(s);\n  }\n  function unassembledSvg() {\n    const sc = mechanismScale();\n    const A = toSvg([0, 0], sc);\n    const B = toSvg([state.g, 0], sc);\n    let s = grid();\n    s += rod('#1f2937', 18, A, B);\n    s += linkLabel('g', '#1f2937', A, B, [0, 42]);\n    s += groundPivot('A', A);\n    s += groundPivot('B', B);\n    s += centeredText(500, 256, '#b91c1c', 26, 'No real assembly for this length set or angle.');\n    s += centeredText(500, 296, '#64748b', 18, 'Adjust the link lengths until V ≤ 0.');\n    return svgFrame(s);\n  }\n\n  installEvents();\n  syncSliderInputs();\n  render();\n  window.requestAnimationFrame(animationFrame);\n})();"
